const groupes   = consoliderGroupes(lignes);
const resultats = groupes.map(analyserGroupe);
const stats     = calculerStats(resultats, lignes);

const output = resultats.map(r => ({ json: r }));

output.unshift({
  json: {
    _type:     "RESUME",
    ...stats,
    timestamp: new Date().toISOString(),
  }
});

return output;

