    &nbsp;|&nbsp; ${new Date(resume.timestamp).toLocaleString('fr-FR')}
  </div>
</div>`.trim();

  // Le sujet reflète le nombre de relances et un éventuel seuil atteint
  const suffixeRelance = relances.nb_envois ? ` — Relance n°${relances.nb_envois}` : '';
  const alerteSeuil = seuilsAtteints.length > 0 ? ` — ⛔ SEUIL ${seuilsAtteints.join('/')} ATTEINT` : '';

  result.push({
    json: {
      to: destinataires.join(','),
      subject: `⚠ ÉCART FACTURE — ${facture} — ${resume.total_vrais_ecarts} article(s) — Δ +${fmt(resume.somme_delta_montant_reel)} DH${suffixeRelance}${alerteSeuil}`,
      message: htmlMessage,
      meta: {
        num_facture:         facture,
        dffs:                resume.dffs,
        has_ecart:           true,
        total_ecarts:        resume.total_vrais_ecarts,
        delta_montant_total: resume.somme_delta_montant_reel,
