}

return result;

const allItems = $input.all();

const destinataires = [
  'responsable.comptabilite@jbel-annour.ma',
  'archiviste.4@jbel-annour.ma',
  'responsable.magasin@jbel-annour.ma',
  'acheteur.1@jbel-annour.ma'
];

const fmt = (n) => parseFloat(n || 0).toLocaleString('fr-FR', {
  minimumFractionDigits: 2, maximumFractionDigits: 2
});

// ── BADGES SUIVI DES RELANCES ───────────────────────────────────
const badgeStatutRelance = (statut) => {
  if (statut === 'SOUS_DELAI')
    return `<span style="background:#d5f5e3;color:#1e8449;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">✅ SOUS DÉLAI</span>`;
  if (statut === 'DEPASSE' || statut === 'SEUIL_ATTEINT')
    return `<span style="background:#fadbd8;color:#922b21;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">⛔ SEUIL ATTEINT</span>`;
  return `<span style="background:#fef9e7;color:#9a7d0a;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">⚠ ${statut || '—'}</span>`;
};

const palierRow = (label, p) => {
  if (!p) return '';
  const proche = !p.atteint && p.jours_restants <= 3;
  const statutBadge = p.atteint
    ? `<span style="background:#fadbd8;color:#922b21;padding:2px 9px;border-radius:10px;font-size:11px;font-weight:700;">⛔ ATTEINT</span>`
    : (proche
        ? `<span style="background:#fdebd0;color:#784212;padding:2px 9px;border-radius:10px;font-size:11px;font-weight:700;">⚠ PROCHE</span>`
        : `<span style="background:#d5f5e3;color:#1e8449;padding:2px 9px;border-radius:10px;font-size:11px;font-weight:700;">✅ OK</span>`);
  return `
    <tr style="background:${p.atteint ? '#fef5f5' : (proche ? '#fffaf0' : '#fff')};">
      <td style="padding:7px 9px;border-bottom:1px solid #eee;font-weight:600;">${label}</td>
      <td style="padding:7px 9px;border-bottom:1px solid #eee;text-align:center;">${p.seuil_jours}j</td>
      <td style="padding:7px 9px;border-bottom:1px solid #eee;text-align:center;">${p.date_limite || '—'}</td>
      <td style="padding:7px 9px;border-bottom:1px solid #eee;text-align:center;font-weight:700;color:${p.atteint ? '#922b21' : (proche ? '#c0392b' : '#333')};">${p.jours_restants}j</td>
      <td style="padding:7px 9px;border-bottom:1px solid #eee;text-align:center;">${statutBadge}</td>
    </tr>`;
};

function extraireItems(allItems) {
  const rows = [];
  for (const item of allItems) {
    const val = item.json;
    if (val && Array.isArray(val.data)) {
      for (const d of val.data) rows.push(d);
    } else {
      rows.push(val);
    }
  }
  return rows;
}

const rows    = extraireItems(allItems);
const resumes = rows.filter(r => r._type === 'RESUME');
const lignes  = rows.filter(r => !r._type);

const lignesParFacture = {};
for (const ligne of lignes) {
  const f = ligne.num_facture;
  if (!lignesParFacture[f]) lignesParFacture[f] = [];
  lignesParFacture[f].push(ligne);
}

const result = [];

for (const resume of resumes) {
  if (resume.total_vrais_ecarts !== 0) continue;

  const facture  = resume.num_facture;
  const articles = lignesParFacture[facture] || [];
  const ctrl     = resume.controle_total_facture || {};
  const relances = resume.suivi_relances || {};

  // Articles dont le BR couvre plusieurs factures (nb_lignes_erp > 1 ou réception partielle)
  const articlesMultiBR = articles.filter(a =>
    a.reception_partielle_facturee_total === true ||
