// Récupère les infos de la facture depuis le node précédent (avant Send Email)
// et le résultat de Nodemailer pour savoir si l'envoi a réussi
const items = $input.all();
const results = [];

for (const item of items) {
  // Adapte ces chemins selon ton workflow réel
  const numero_facture = item.json.numero_facture 
    ?? $('If6').item.json.numero_facture;
  const numero_dff = item.json.numero_dff 
    ?? $('If6').item.json.numero_dff;

  const nodemailerResult = item.json.accepted ? item.json : item.json[0];
  const isSuccess = nodemailerResult?.accepted?.length > 0;

  if (!isSuccess) {
    // On ne compte pas un envoi raté
    continue;
  }

  results.push({
    json: {
      numero_facture,
      numero_dff,
      now: new Date().toISOString().slice(0, 19).replace('T', ' '),
    }
  });
}

return results;
